import React, { useState } from "react";
import "../styles/GeneralChat.css";

const GeneralChat = () => {
  const [messages, setMessages] = useState([
    { sender: "bot", text: "Hi 👋 I’m your AI mental health assistant. How are you feeling today?" }
  ]);
  const [input, setInput] = useState("");

  const sendMessage = () => {
    if (!input.trim()) return;

    const userMessage = { sender: "user", text: input };

    // Simple AI logic (we’ll upgrade later)
    const botReply = {
      sender: "bot",
      text: generateBotReply(input)
    };

    setMessages([...messages, userMessage, botReply]);
    setInput("");
  };

  const generateBotReply = (msg) => {
    msg = msg.toLowerCase();

    if (msg.includes("sad")) return "I’m really sorry you’re feeling sad 💜 Do you want to talk about what happened?";
    if (msg.includes("stress")) return "Stress can be overwhelming. Let’s slow down together. What’s causing it?";
    if (msg.includes("happy")) return "That’s wonderful to hear 😊 What made you feel happy today?";

    return "I’m listening. Tell me more about how you’re feeling.";
  };

  return (
    <div className="chat-container">
      <h2>General Chat</h2>

      <div className="chat-box">
        {messages.map((msg, index) => (
          <div key={index} className={`chat-message ${msg.sender}`}>
            {msg.text}
          </div>
        ))}
      </div>

      <div className="chat-input">
        <input
          type="text"
          placeholder="Type how you feel..."
          value={input}
          onChange={(e) => setInput(e.target.value)}
        />
        <button onClick={sendMessage}>Send</button>
      </div>
    </div>
  );
};

export default GeneralChat;
